10	type Scenario = {
11	  customer: { yearsWithMHPCO: number };
12	  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
13	};
14	
15	type QuoteResult = { premium: number };
16	
17	const quotePremium = (items: Array<{ type: string }>): QuoteResult => {
18	  if (items.length === 0) return { premium: PROCESSING_FEE };
19	  const base = BASE_PREMIUMS[items[0].type];
20	  const firstInsurance = base * FIRST_INSURANCE_RATE;
21	  return { premium: base + firstInsurance + PROCESSING_FEE };
22	};
23	
24	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
25	  const results = scenario.steps.map((step) => quotePremium(step.items));
26	  return { results };
27	};
